func TestMaskKey(t *testing.T) {
	tests := []struct {
		name  string
		input string
		want  string
	}{
		{"empty", "", "(not set)"},
		{"short (4)", "abcd", "****"},
		{"short (8)", "abcdefgh", "****"},
		{"long (32)", "ABCDefghIJKLmnopQRSTuvwxYZABCDEF", "ABCD****CDEF"},
	}
	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			assert.Equal(t, tc.want, maskKey(tc.input))
		})
	}
}

